    def event_dispatch(self, socket, msg):
        sequencer_event_map = {
            events.SEQUENCE_START: 'on_sequence_start',
            events.SEQUENCE_END: 'on_sequence_end',
            events.ITEM_START: 'on_item_start',
            events.ITEM_FINISH: 'on_item_finish',
            events.ATTRIBUTE_FOUND: 'on_attribute_found',
            events.SEQUENCE_LOADED: 'on_sequence_loaded'
        }
        if len(msg) == 5:
            topic, ts, level, origin, data = msg[:]
            if int(level) > levels.REPORTER:
                return None
            report = ReporterProtocol.parse_report(data)
            if report:
                func_name = sequencer_event_map.get(report.event)
                if func_name:
                    func = getattr(self, func_name, None)
                    if callable(func):
                        func(self.site, report.data)
                else:
                    print('Unrecognized event; {}'.format(report.event), msg)
                if report.event == events.SEQUENCE_END:
                    # server instance is attach to PuddingLogger at line-100 
                    _thread.start_new_thread(self.on_logs_ready, (self.site, self.server.get_log_paths(self.site)))


    def on_logs_ready(self, site, data):
        site_dut = self.dut
        fixture_id = self.fixture_id
        vendor_id = self.vendor_id
        result = self.result
        log_file_name = self.dut.log_file_name
        log_folder = self.log_folder
        uut = site_dut.uut
        sn = self.dut.sn
        upload_log_file = site_dut.log_file
        self.user_home = os.path.expanduser('~')
        f = open(f"{self.user_home}/testerconfig/mes_config.json", 'r')
        self.gh_info = json.load(f)
        self.mes_skip = self.gh_info.get('mes_skip')
        f.close()


   
        if result >= 0:
            upload_log_file.write('=======================>add log:' + str(data) + '\n')
            upload_log_file.flush()
            site_dut.log_paths.extend(data)
            site_dut.log_paths = list(set(site_dut.log_paths)) # remove duplicated file path

            upload_log_file.write('=======================>total logs:' + str(site_dut.log_paths) + '\n')
            upload_log_file.flush()
            if sn is None or len(sn) == 0:
                upload_log_file.write('=======================>UUT cancelled due to empty SN')
                upload_log_file.flush()
                upload_log_file.close()
                self.cleanup(site)
                return
            try:
                if result:
                    zipped_logs = self.zip_logs(site_dut.log_paths, log_folder, sn, upload_log_file, 'PASS')
                else:
                    zipped_logs = self.zip_logs(site_dut.log_paths, log_folder, sn, upload_log_file, 'FAIL')
                upload_log_file.write('=======================>zipped_logs:' + str(zipped_logs) + '\n')
                upload_log_file.flush()
                if zipped_logs:
                    shutil.rmtree(os.path.splitext(zipped_logs)[0])
                else:
                    self.reporter.report(events.REPORT_ERROR, site=site, error_code=reporter.ZIPPED_FILE_ERROR,
                                         error_msg=str(site_dut.log_paths) + ' not found in ' + str(log_folder))
            except Exception as e:
                upload_log_file.write('=======================>error creating zipped file: ' + str(e))
                upload_log_file.write(traceback.format_exc())
                upload_log_file.flush()
                self.reporter.report(events.REPORT_ERROR, site=site, error_code=reporter.ZIPPED_FILE_ERROR,
                                     error_msg=str(e))
            finally:
                if get_mes_status():
                    mes = UploadMES()
                    sn = site_dut.sn
                    result = "PASS" if self.result else "FAIL"
                    test_data = []
                    fixture_id = self.fixture_id or ''
                    error_code = "0000"
                    error_msg = ""
                    if not self.result:
                        if self.error_code_name:
                            error_code = mes.get_error_code(self.error_code_name + ".csv", self.fail_test_item)
                            if error_code:
                                error_code = self.error_code_name+error_code
                        if not error_code:
                            error_code = "0000"
                        error_msg = self.fail_test_item
                    if result == 'PASS' or not self.mes_skip:
                        upload_log_file = self.dut.log_file
                        upload_log_file.write("sn: {}\ntest_data:{}\n result: {} \nfixture_id: {} \nerror_code: {} \nerror_msg: {}\n".format(sn,test_data,result,fixture_id,error_code,error_msg))
                        state, response = mes.send_data(sn,test_data,result,fixture_id,error_code,error_msg)
                        upload_log_file.write("Response \nmes status: {}\n; response: {}\n".format(state, response))

                upload_log_file.close()
        self.cleanup(site)

    def cleanup(self, site):
        site_dut = self.dut
        site_dut.log_paths = []
        self.result = None
        self.logs = ''
